   360→
   361→    // ── Helper: state badge class ─────────────────────────────────────────────
   362→
   363→    const ACTIVE_STATES = new Set([
   364→      'cooking', 'brewing', 'painting', 'working', 'tending', 'reading', 'on',
   365→    ]);
   366→    const DONE_STATES = new Set(['done', 'ready', 'open', 'cozy', 'resting']);
   367→
   368→    function badgeClass(state) {
   369→      if (state === 'idle')         return 'idle';
   370→      if (DONE_STATES.has(state))   return 'done';
   371→      if (ACTIVE_STATES.has(state)) return 'active';
