   375→    // ── Log helper ────────────────────────────────────────────────────────────
   376→
   377→    function pushLog(objectId, fromState, toState, trigger) {
   378→      log.unshift({ objectId, fromState, toState, trigger, time: simEngine.getSimTimeString() });
   379→      if (log.length > MAX_LOG) log.length = MAX_LOG;
