   394→      const from = obj.state;
   395→      const ev = simEngine.objectEngine.interact(objectId, action);
   396→      if (ev) {
   397→        pushLog(objectId, from, ev.state, action);
   398→        prevStateMap.set(objectId, ev.state);
   399→        updateObjectCard(obj);
   400→      }
   401→    };
