   427→
   428→    function updateObjectCard(obj) {
   429→      const badge      = document.getElementById(`badge-${obj.id}`);
   430→      const timerBar   = document.getElementById(`timerbar-${obj.id}`);
   431→      const timerFill  = document.getElementById(`timerfill-${obj.id}`);
   432→      const timerText  = document.getElementById(`timertext-${obj.id}`);
   433→      const intDiv     = document.getElementById(`int-${obj.id}`);
   434→      if (!badge) return;
   435→
   436→      const prevState = badge.dataset.state;
   437→      const stateChanged = prevState !== obj.state;
   438→
   439→      if (stateChanged) {
   440→        badge.textContent = obj.state;
   441→        badge.className = `state-badge ${badgeClass(obj.state)}`;
   442→        badge.dataset.state = obj.state;
   443→
   444→        // Rebuild interaction buttons on state change
   445→        const stateDef = obj.states[obj.state];
   446→        const actions = Object.keys(stateDef?.transitions || {});
   447→        intDiv.innerHTML = actions.map(a =>
   448→          `<button onclick="window._dbInteract('${obj.id}','${a}')">${a}</button>`
   449→        ).join('');
   450→      }
   451→
   452→      // Timer bar (update every frame regardless of state change)
   453→      const stateDef = obj.states[obj.state];
   454→      const hasTimer = !!(stateDef?.auto_next && obj.autoTimer > 0);
   455→      if (hasTimer) {
   456→        const totalMs = stateDef.auto_next.after * 1000;
   457→        const pct = Math.max(0, Math.min(100, (1 - obj.autoTimer / totalMs) * 100));
   458→        timerBar.style.display = '';
   459→        timerFill.style.width  = `${pct.toFixed(1)}%`;
   460→        timerText.style.display = '';
   461→        timerText.textContent   = `${Math.ceil(obj.autoTimer / 1000)}s remaining`;
   462→      } else {
   463→        timerBar.style.display  = 'none';
   464→        timerText.style.display = 'none';
   465→      }
   466→    }
