   482→
   483→      const targetName = char.interactTarget
   484→        ? (simEngine.objectEngine.getById(char.interactTarget)?.name ?? char.interactTarget)
   485→        : char.targetObjectId
   486→          ? (simEngine.objectEngine.getById(char.targetObjectId)?.name ?? char.targetObjectId)
   487→          : '—';
   488→
   489→      // AI decision cooldown timer
   490→      let cooldownHtml = '';
   491→      if (aiEngine.enabled) {
   492→        const remaining  = Math.max(0, aiEngine._timers.get(char.name) ?? aiEngine.decisionIntervalMs);
   493→        const pct        = Math.max(0, Math.min(100, (1 - remaining / aiEngine.decisionIntervalMs) * 100));
   494→        const secRemaining = Math.ceil(remaining / 1000);
   495→        cooldownHtml = `
