   542→    function renderEventLog() {
   543→      if (!logDirty) return;
   544→      logDirty = false;
   545→
   546→      const el = document.getElementById('event-log');
   547→      if (log.length === 0) {
   548→        el.innerHTML = '<div style="color:#555;padding:4px 0">No events yet.</div>';
   549→        return;
   550→      }
   551→      el.innerHTML = log.slice(0, 80).map(e => {
   552→        if (e.type === 'ai') {
   553→          const targetStr   = e.target   ? ` \u2192 ${e.target}` : '';
   554→          const dialogueStr = e.dialogue ? ` \u201c${e.dialogue}\u201d` : '';
   555→          return `
   556→            <div class="log-entry ai">
