   560→              <span class="log-tag ai">AI</span>
   561→            </div>
   562→          `;
   563→        }
   564→        return `
   565→          <div class="log-entry ${e.trigger === 'auto' ? 'auto' : 'interaction'}">
   566→            <span class="log-time">${e.time}</span>
   567→            <span class="log-obj">${e.objectId}</span>
   568→            <span class="log-transition">${e.fromState} &rarr; ${e.toState}</span>
   569→            <span class="log-tag ${e.trigger === 'auto' ? 'auto' : 'use'}">${e.trigger}</span>
   570→          </div>
   571→        `;
   572→      }).join('');
   573→    }
   574→
   575→    // ── Tick loop ─────────────────────────────────────────────────────────────
   576→
   577→    function tick(ts) {
   578→      requestAnimationFrame(tick);
   579→
   580→      if (!paused && lastTs !== null) {
   581→        const realDelta = (ts - lastTs) * speed;
   582→
   583→        // Snapshot states before update
   584→        const snap = new Map();
   585→        for (const obj of simEngine.objectEngine.getAll()) snap.set(obj.id, obj.state);
   586→
   587→        // Advance simulation
   588→        simEngine.update(realDelta);
   589→
   590→        // Detect auto-transitions
   591→        for (const obj of simEngine.objectEngine.getAll()) {
   592→          if (snap.get(obj.id) !== obj.state) {
   593→            pushLog(obj.id, snap.get(obj.id), obj.state, 'auto');
   594→            prevStateMap.set(obj.id, obj.state);
   595→          }
   596→          updateObjectCard(obj);
   597→        }
   598→
   599→        // Update character cards
   600→        simEngine.characters.forEach((char, i) => updateCharacterCard(char, i));
   601→      }
   602→
   603→      lastTs = ts;
   604→
   605→      // Clock
   606→      document.getElementById('clock').textContent = simEngine.getSimTimeString();
   607→
   608→      // Event log (only when dirty)
   609→      renderEventLog();
   610→    }
   611→
   612→    // ── Init ──────────────────────────────────────────────────────────────────
   613→
   614→    initObjectCards();
   615→    initCharacterCards();
   616→    requestAnimationFrame(tick);
   617→  </script>
