     1→/**
     2→ * AIEngine.js — LLM-driven decision engine.
     3→ *
     4→ * When `endpoint` is null (default) the engine is disabled and characters
     5→ * fall back to random wander controlled by SimulationEngine.
     6→ *
     7→ * To enable, pass an endpoint URL and optionally an API key:
     8→ *   new AIEngine({ endpoint: 'https://api.anthropic.com/v1/messages', apiKey: '...' })
     9→ *
    10→ * The engine polls each character independently on a configurable interval.
    11→ * Responses are expected as JSON with this shape:
    12→ *   { "action": "move|interact|idle",
    13→ *     "targetId": "object_id",          // for interact
    14→ *     "targetTile": { "tx": 5, "ty": 9 }, // for move
    15→ *     "dialogue": "optional speech",
    16→ *     "description": "what the character is doing" }
    17→ */
    18→
    19→export class AIEngine {
    20→  /**
    21→   * @param {object}  [config]
    22→   * @param {string}  [config.endpoint]            - full URL of LLM API endpoint
    23→   * @param {string}  [config.apiKey]              - bearer token / API key
    24→   * @param {string}  [config.model]               - model ID (for Anthropic-style APIs)
    25→   * @param {number}  [config.decisionIntervalMs]  - ms between decisions per char (default 30 000)
    26→   */
    27→  constructor(config = {}) {
    28→    this.endpoint           = config.endpoint           || null;
    29→    this.apiKey             = config.apiKey             || null;
    30→    this.model              = config.model              || 'claude-sonnet-4-6';
    31→    this.decisionIntervalMs = config.decisionIntervalMs || 30_000;
    32→    this.onDecision         = config.onDecision         || null;
    33→
    34→    this.enabled = !!this.endpoint;
    35→
    36→    // Per-character countdown timers  { name → ms until next decision }
    37→    this._timers = new Map();
    38→    // Prevent overlapping requests  { name → true }
    39→    this._pending = new Set();
    40→  }
    41→
    42→  // ── Called by SimulationEngine each frame ─────────────────────────────────
    43→
    44→  update(deltaMs, characters, objects, simState) {
    45→    if (!this.enabled) return;
    46→
    47→    for (const char of characters) {
    48→      let t = this._timers.get(char.name) ?? 0;
    49→      t -= deltaMs;
    50→
    51→      if (t <= 0 && !this._pending.has(char.name)) {
    52→        this._timers.set(char.name, this.decisionIntervalMs);
    53→        this._requestDecision(char, objects, simState);
    54→      } else {
    55→        this._timers.set(char.name, t);
    56→      }
    57→    }
    58→  }
    59→
    60→  // ── Internal ──────────────────────────────────────────────────────────────
    61→
    62→  async _requestDecision(character, objects, simState) {
    63→    this._pending.add(character.name);
    64→
    65→    try {
    66→      const nearbyObjects = objects
    67→        .filter(obj => {
    68→          const dx = obj.tx - character.tx;
    69→          const dy = obj.ty - character.ty;
    70→          return Math.sqrt(dx * dx + dy * dy) <= 8;
    71→        })
    72→        .map(o => ({ id: o.id, label: o.label, state: o.state }));
    73→
    74→      const systemPrompt =
    75→        `You are ${character.label}, a character in a cosy Japanese home simulation. ` +
    76→        `Decide what to do next based on your mood (${character.mood}/100) and energy (${character.energy}/100). ` +
    77→        `Reply ONLY with valid JSON — no markdown fences, no extra text.`;
    78→
    79→      const userPrompt =
    80→        `Sim time: ${simState.timeString}. ` +
    81→        `You are at tile (${Math.round(character.tx)}, ${Math.round(character.ty)}). ` +
    82→        `Current action: ${character.action}. ` +
    83→        `Nearby objects: ${JSON.stringify(nearbyObjects)}. ` +
    84→        `Choose one action:\n` +
    85→        `  { "action": "move",     "targetTile": {"tx": N, "ty": N}, "dialogue": "...", "description": "..." }\n` +
    86→        `  { "action": "interact", "targetId": "object_id",          "dialogue": "...", "description": "..." }\n` +
    87→        `  { "action": "idle",                                        "dialogue": "...", "description": "..." }`;
    88→
    89→      const headers = { 'Content-Type': 'application/json' };
    90→
    91→      // Build body — compatible with Anthropic Messages API shape by default;
    92→      // swap for OpenAI chat completions if needed by changing endpoint.
    93→      const body = JSON.stringify({
    94→        model: this.model,
    95→        max_tokens: 256,
    96→        system: systemPrompt,
    97→        messages: [{ role: 'user', content: userPrompt }],
    98→      });
    99→
   100→      const res = await fetch(this.endpoint, { method: 'POST', headers, body });
   101→
   102→      if (!res.ok) {
   103→        console.warn(`[AIEngine] ${character.name}: HTTP ${res.status}`);
   104→        return;
   105→      }
   106→
   107→      const data = await res.json();
   108→
   109→      // Extract text from Anthropic-style response; fall back to OpenAI style
   110→      let text = data?.content?.[0]?.text     // Anthropic
