   208→    </div>
   209→
   210→    <div id="controls">
   211→      <button id="btn-pause">&#9646;&#9646; Pause</button>
   212→      <div class="ctrl-sep"></div>
   213→      <span class="ctrl-label">Speed:</span>
   214→      <button class="speed-btn active" data-speed="1">1x</button>
   215→      <button class="speed-btn" data-speed="2">2x</button>
   216→      <button class="speed-btn" data-speed="4">4x</button>
   217→      <div class="ctrl-sep"></div>
   218→      <button id="btn-reset">&#8635; Reset</button>
   219→    </div>
   220→
   221→    <div class="main-grid">
   222→      <div class="left-col">
   223→        <div>
   224→          <div class="section-title">Objects (10)</div>
   225→          <div id="objects-grid"></div>
   226→        </div>
   227→        <div>
   228→          <div class="section-title">Characters</div>
   229→          <div id="characters-grid"></div>
   230→        </div>
   231→      </div>
   232→      <div id="log-section">
   233→        <div class="section-title">Event Log</div>
   234→        <div id="event-log"><div style="color:#555;padding:4px 0">No events yet.</div></div>
   235→      </div>
   236→    </div>
   237→  </div>
   238→
   239→  <script type="module">
   240→    import { ObjectEngine, OBJECT_DEFS } from './src/objects.js';
   241→    import { SimulationEngine } from './src/Engine.js';
   242→    import { Character } from './src/Character.js';
   243→    import { AIEngine } from './src/AIEngine.js';
   244→
   245→    // ── Walkable grid (mirrors scene.js) ──────────────────────────────────────
   246→
   247→    const GRID_COLS = 19;
   248→    const GRID_ROWS = 13;
   249→
   250→    function buildWalkableGrid() {
   251→      const grid = [];
   252→      for (let row = 0; row < GRID_ROWS; row++) {
   253→        const r = [];
   254→        for (let col = 0; col < GRID_COLS; col++) {
   255→          r.push(col >= 1 && col <= 17 && row >= 2 && row <= 9);
   256→        }
   257→        grid.push(r);
   258→      }
   259→      // Mark tiles occupied by objects as non-walkable
   260→      for (const def of OBJECT_DEFS) {
   261→        const { tx, ty } = def.position;
   262→        if (ty >= 0 && ty < GRID_ROWS && tx >= 0 && tx < GRID_COLS) {
   263→          grid[ty][tx] = false;
   264→        }
   265→      }
   266→      return grid;
   267→    }
   268→
   269→    // ── Character definitions (mirrors scene.js) ─────────────────────────────
   270→
   271→    const CHARS_CONFIG = [
   272→      { name: 'Amelia', label: 'Maple', tx: 6,  ty: 7,
   273→        dialogue: ['Perfect brew today~', 'Want some tea?'] },
   274→      { name: 'Lucy',   label: 'Sol',   tx: 10, ty: 6,
   275→        dialogue: ['The bonsai looks healthy', 'Such peaceful light...'] },
   276→      { name: 'Ash',    label: 'Nyx',   tx: 13, ty: 5,
   277→        dialogue: ['I need more paint...', 'This light is perfect'] },
   278→    ];
   279→
   280→    // ── Engine setup ──────────────────────────────────────────────────────────
   281→
   282→    const walkable = buildWalkableGrid();
   283→
   284→    const aiEngine = new AIEngine({
   285→      endpoint: '/api/llm',
   286→      model: 'anthropic/claude-3-haiku',
   287→      decisionIntervalMs: 30_000,
   288→      onDecision: (char, decision, objects) => {
   289→        const targetName = decision.targetId
   290→          ? (objects.find(o => o.id === decision.targetId)?.name ?? decision.targetId)
   291→          : decision.targetTile
   292→            ? `(${decision.targetTile.tx},${decision.targetTile.ty})`
   293→            : null;
   294→        pushAILog(char.label, decision.action, targetName, decision.dialogue);
   295→      },
   296→    });
   297→
   298→    const simEngine = new SimulationEngine({ walkable, gridCols: GRID_COLS, gridRows: GRID_ROWS, aiEngine });
   299→
   300→    for (const cfg of CHARS_CONFIG) {
   301→      simEngine.addCharacter(new Character({
   302→        ...cfg, walkable, gridCols: GRID_COLS, gridRows: GRID_ROWS,
   303→      }));
   304→    }
   305→
   306→    // ── UI state ──────────────────────────────────────────────────────────────
   307→
   308→    let paused = false;
   309→    let speed  = 1;
   310→    let lastTs = null;
   311→
   312→    // Event log (newest-first)
   313→    const log = [];
   314→    const MAX_LOG = 150;
   315→    let logDirty = false;
   316→
   317→    // Track previous object states so we can log from→to
   318→    const prevStateMap = new Map();
   319→    for (const obj of simEngine.objectEngine.getAll()) {
   320→      prevStateMap.set(obj.id, obj.state);
   321→    }
   322→
   323→    // ── Controls ──────────────────────────────────────────────────────────────
   324→
   325→    const pauseBtn = document.getElementById('btn-pause');
   326→    pauseBtn.addEventListener('click', () => {
   327→      paused = !paused;
   328→      pauseBtn.innerHTML = paused ? '&#9654; Play' : '&#9646;&#9646; Pause';
   329→      pauseBtn.classList.toggle('active', paused);
   330→      if (!paused) lastTs = null; // avoid time-jump on resume
   331→    });
   332→
   333→    document.querySelectorAll('.speed-btn').forEach(btn => {
   334→      btn.addEventListener('click', () => {
   335→        speed = parseFloat(btn.dataset.speed);
   336→        document.querySelectorAll('.speed-btn').forEach(b => b.classList.remove('active'));
   337→        btn.classList.add('active');
   338→      });
   339→    });
   340→
   341→    document.getElementById('btn-reset').addEventListener('click', () => {
   342→      // Reset object states to defaults
   343→      for (const def of OBJECT_DEFS) {
   344→        const obj = simEngine.objectEngine.getById(def.id);
   345→        if (!obj) continue;
   346→        obj.state = def.state || 'idle';
   347→        obj._resetAutoTimer();
   348→        prevStateMap.set(def.id, obj.state);
   349→      }
   350→      // Reset sim clock
   351→      simEngine.simTimeMs = 8 * 60 * 60 * 1000;
   352→      // Clear log
   353→      log.length = 0;
