        this.ty     = arrived.ty;
      }

      if (this.path.length === 0) {
        this.moveProgress = 0;
        this.action       = 'idle';
        this.wanderTimer  = 3000 + Math.random() * 5000;
        this._playAnim('idle');
      } else {
        this._playWalkAnim();
      }
    } else if (this.action === 'idle') {
