update(deltaMs, characters, objects, simState) {
  if (!this.enabled) return;

  for (const char of characters) {
    let t = this._timers.get(char.name) ?? 0;
    t -= deltaMs;

    // Don't make decisions while character is held at an object; let the
    // timer keep ticking so the cooldown UI stays accurate.
    if (t <= 0 && !this._pending.has(char.name) && char.action !== 'interacting') {
      this._timers.set(char.name, this.decisionIntervalMs);
      this._requestDecision(char, objects, simState);
    } else {
      this._timers.set(char.name, t);
    }
  }
}

// ── Internal ──────────────────────────────────────────────────────────────

function updateCharacterCard(char, i) {
  const card = document.getElementById(`char-${i}`);
  if (!card) return;

  const targetName = char.interactTarget
    ? (simEngine.objectEngine.getById(char.interactTarget)?.name ?? char.interactTarget)
    : char.targetObjectId
      ? (simEngine.objectEngine.getById(char.targetObjectId)?.name ?? char.targetObjectId)
      : '—';

  // Hold countdown timer (shown while character is locked at an object)
  let holdHtml = '';
  if (char.action === 'interacting' && char.interactTimer > 0 && char.interactTimerMax > 0) {
    const pct = Math.max(0, Math.min(100, (1 - char.interactTimer / char.interactTimerMax) * 100));
    holdHtml = `
      <div class="char-row" style="margin-top:4px">
        <span>Hold</span>
        <span class="char-value">${Math.ceil(char.interactTimer / 1000)}s</span>
      </div>
      <div class="stat-bar">
        <div class="stat-fill hold-timer" style="width:${pct.toFixed(1)}%"></div>
      </div>
    `;
  }

  // AI decision cooldown timer
  let cooldownHtml = '';
  if (aiEngine.enabled) {
    const remaining  = Math.max(0, aiEngine._timers.get(char.name) ?? aiEngine.decisionIntervalMs);
    const pct        = Math.max(0, Math.min(100, (1 - remaining / aiEngine.decisionIntervalMs) * 100));
    const secRemaining = Math.ceil(remaining / 1000);
    cooldownHtml = `
      <div class="char-row" style="margin-top:4px">
        <span>AI next</span>
        <span class="char-value">${secRemaining}s</span>
      </div>
      <div class="stat-bar">
        <div class="stat-fill ai-cooldown" style="width:${pct.toFixed(1)}%"></div>
      </div>
    `;
  }

  card.innerHTML = `
    <div class="character-name">${char.label}</div>
    <div class="char-row">
      <span>Action</span>
      <span class="action-badge ${char.action}">${char.action}</span>
    </div>
    <div class="char-row">
      <span>Position</span>
      <span class="char-value">(${Math.round(char.tx)}, ${Math.round(char.ty)})</span>
    </div>
    <div class="char-row">
      <span>Facing</span>
      <span class="char-value">${char.facing}</span>
    </div>
    <div class="char-row">
      <span>Target</span>
      <span class="char-value">${targetName}</span>

